const { ApolloServer, gql } = require('apollo-server');
const { findInvoiceById } = require('./invoiceService'); // Assume this service fetches invoice data

// Define the GraphQL schema
const typeDefs = gql`
  type Invoice {
    id: ID!
    amount: Float!
    date: String!
    customerName: String!
  }

  type Query {
    getInvoiceById(id: ID!): Invoice
  }
`;

// Implement the resolvers
const resolvers = {
  Query: {
    getInvoiceById: async (_, { id }, context) => {
      // Ensure the user is authenticated
      if (!context.user) throw new Error('Unauthorized');

      // Validate the ID format
      if (!/^\d+$/.test(id)) throw new Error('Invalid ID format');

      // Fetch the invoice details
      const invoice = await findInvoiceById(id);

      // Handle case where invoice is not found
      if (!invoice) throw new Error('Invoice not found');

      return invoice;
    }
  }
};

// Create the Apollo Server instance
const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Assume user is added to the request by authentication middleware
    return { user: req.user };
  },
  formatError: (err) => {
    // Prevent detailed error messages from being exposed
    return new Error('Internal server error');
  }
});

// Start the server
server.listen().then(({ url }) => {
  console.log(`Server ready at ${url}`);
});